3947 //
3948 //   %dec = add i32 %x, -1
3949 //   %ctlz = tail call i32 @llvm.ctlz.i32(i32 %dec, i1 false)
3950 //   %sub = sub i32 32, %ctlz
3951 //   %shl = shl i32 1, %sub
3952 //   %ugt = icmp ugt i32 %x, 1
3953 //   %sel = select i1 %ugt, i32 %shl, i32 1
3954 //
3955 // into:
3956 //
3957 //   %dec = add i32 %x, -1
3958 //   %ctlz = tail call i32 @llvm.ctlz.i32(i32 %dec, i1 false)
3959 //   %neg = sub i32 0, %ctlz
3960 //   %masked = and i32 %ctlz, 31
3961 //   %shl = shl i32 1, %sub
3962 //
3963 // Note that the select is optimized away while the shift count is masked with
3964 // 31.  We handle some variations of the input operand like std::bit_ceil(X +
3965 // 1).
3966 static Instruction *foldBitCeil(SelectInst &SI, IRBuilderBase &Builder,
3967                                 InstCombinerImpl &IC) {
