3975   CmpPredicate Pred;
3976   const APInt *Cond1;
3977   Value *Cond0, *Ctlz, *CtlzOp;
3978   if (!match(SI.getCondition(), m_ICmp(Pred, m_Value(Cond0), m_APInt(Cond1))))
3979     return nullptr;
3980 
3981   if (match(TrueVal, m_One())) {
3982     std::swap(FalseVal, TrueVal);
3983     Pred = CmpInst::getInversePredicate(Pred);
3984   }
3985 
3986   bool ShouldDropNoWrap;
3987 
3988   if (!match(FalseVal, m_One()) ||
3989       !match(TrueVal,
3990              m_OneUse(m_Shl(m_One(), m_OneUse(m_Sub(m_SpecificInt(BitWidth),
3991                                                     m_Value(Ctlz)))))) ||
3992       !match(Ctlz, m_Intrinsic<Intrinsic::ctlz>(m_Value(CtlzOp), m_Value())) ||
3993       !isSafeToRemoveBitCeilSelect(Pred, Cond0, Cond1, CtlzOp, BitWidth,
3994                                    ShouldDropNoWrap))
